# A tool definition has three required keys: name, description, input_schema.
# The input_schema is a JSON Schema object with type, properties, and required.

READ_FILE_TOOL = {
    "name": "read_file",
    "description": (
        "Read the full contents of a file. "
        "Use this before writing to understand the current state of a file. "
        "Returns the file contents as a string."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "path": {
                "type": "string",
                "description": "Absolute path to the file to read.",
            },
        },
        "required": ["path"],
    },
}

WRITE_FILE_TOOL = {
    "name": "write_file",
    "description": (
        "Write or overwrite a file with the given content. "
        "Always read the file first with read_file to avoid losing existing content. "
        "Returns the path that was written."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "path": {
                "type": "string",
                "description": "Absolute path to write.",
            },
            "content": {
                "type": "string",
                "description": "Complete new content of the file.",
            },
        },
        "required": ["path", "content"],
    },
}

RUN_TESTS_TOOL = {
    "name": "run_tests",
    "description": (
        "Run the test suite with pytest. "
        "Call this after any file change to verify correctness. "
        "Returns the pytest output including pass/fail counts."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
