from dataclasses import dataclass, field
from typing import Any


@dataclass
class ToolParam:
    """One parameter in a tool's input schema."""
    name: str
    type: str
    description: str
    required: bool = True


@dataclass
class ToolDef:
    """
    A typed tool definition. Serialises to the dict shape expected by
    client.messages.create(tools=[...]).
    """
    name: str
    description: str
    params: list[ToolParam] = field(default_factory=list)

    def to_dict(self) -> dict[str, Any]:
        properties = {
            p.name: {"type": p.type, "description": p.description}
            for p in self.params
        }
        required = [p.name for p in self.params if p.required]
        return {
            "name": self.name,
            "description": self.description,
            "input_schema": {
                "type": "object",
                "properties": properties,
                "required": required,
            },
        }


# Build the same read_file tool using the dataclass
read_file = ToolDef(
    name="read_file",
    description=(
        "Read the full contents of a file. "
        "Use this before writing to understand the current state of a file."
    ),
    params=[
        ToolParam(name="path", type="string", description="Absolute path to the file."),
    ],
)

write_file = ToolDef(
    name="write_file",
    description=(
        "Write or overwrite a file. "
        "Always read first with read_file to avoid data loss."
    ),
    params=[
        ToolParam(name="path", type="string", description="Absolute path to write."),
        ToolParam(name="content", type="string", description="Full new content of the file."),
    ],
)

from dataclasses import dataclass, field
from typing import Callable


@dataclass
class ToolInventory:
    """
    The complete set of tools for one agent run.
    Stores both the definition (for the API call) and the implementation
    (for dispatching tool_use blocks).
    """
    _tools: dict[str, tuple[dict, Callable]] = field(default_factory=dict)

    def register(self, definition: ToolDef, implementation: Callable) -> None:
        self._tools[definition.name] = (definition.to_dict(), implementation)

    def definitions(self) -> list[dict]:
        """Return the list of dicts for client.messages.create(tools=...)."""
        return [defn for defn, _ in self._tools.values()]

    def dispatch(self, name: str, input: dict) -> str:
        """Call the implementation for a tool_use block."""
        if name not in self._tools:
            raise ValueError(f"Unknown tool: {name!r}. Available: {list(self._tools)}")
        _, impl = self._tools[name]
        return impl(**input)

    def names(self) -> list[str]:
        return list(self._tools.keys())


# Build and use an inventory
inventory = ToolInventory()
inventory.register(read_file, lambda path: open(path).read())
inventory.register(write_file, lambda path, content: open(path, "w").write(content) or path)

# In the agent loop:
import anthropic
client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=4096,
    tools=inventory.definitions(),      # definitions go to the API
    messages=[{"role": "user", "content": "Read src/app.py"}],
)

# Dispatch any tool_use blocks
for block in response.content:
    if block.type == "tool_use":
        result = inventory.dispatch(block.name, block.input)
